var newsData = {"finance": [{"title": "月之暗面完成20亿美元新融资", "summary": "估值突破200亿美元，成为AI领域超级独角兽", "source": "36氪", "date": "5月7日", "badge": "热点", "detail": "月之暗面（Moonshot AI）即将完成新一轮20亿美元融资，本轮融资后公司估值将超过200亿美元，跻身全球AI独角兽前列。\n\n投资方包括腾讯、阿里巴巴等战略投资者以及多家头部美元基金。此前，月之暗面已完成多轮融资，累计融资额超过30亿美元。公司成立于2023年，由前清华大学研究人员杨植麟创立，专注于大语言模型研发。\n\n公司旗下Kimi智能助手月活已突破3000万，成为国内增长最快的AI应用之一。Kimi以其超长上下文窗口（支持200万字上下文）和出色的中文理解能力著称，在文档分析、代码辅助、内容创作等场景表现优异。本轮融资将主要用于模型训练、人才引进和商业化拓展。", "link": "https://36kr.com"}, {"title": "李嘉诚抛售资产套现约455亿", "summary": "持续优化资产结构，聚焦核心业务", "source": "新浪财经", "date": "5月7日", "badge": "", "detail": "李嘉诚家族通过旗下长和系公司近期完成多笔资产出售，累计套现约455亿港元，引发市场广泛关注。\n\n出售资产包括英国水务公司Northumbrian Water、欧洲港口资产以及亚洲部分地产项目。这是李嘉诚近年来最大规模的资产处置行动之一，显示出其对全球经济不确定性和地缘政治风险的谨慎态度。\n\n市场分析认为，这是李嘉诚一贯的反周期操作策略。在经济繁荣期积累资产，在不确定性增加时变现，将资金转向更安全的领域。近期，长和系公司的现金储备已达到历史高位，为未来可能出现的投资机会做好了准备。", "link": "https://finance.sina.com.cn"}, {"title": "宝马一季度利润降25%", "summary": "至23亿欧元，受中国市场竞争加剧影响", "source": "宝马官网", "date": "5月7日", "badge": "", "detail": "宝马集团发布2025年第一季度财报，业绩表现不及市场预期。营收同比下降15.2%至366亿欧元，净利润下降25%至23亿欧元，毛利率也承压下行。\n\n中国作为宝马全球最大单一市场，销量下滑17.2%，成为拖累全球业绩的主要因素。比亚迪、蔚来、理想等本土电动车品牌通过激烈的价格战不断蚕食市场份额，宝马在传统燃油车领域的优势正在被削弱。\n\n为应对挑战，宝马宣布将在华推出更多纯电车型，包括全新iX3、i5等车型，并计划将沈阳生产基地的产能向新能源倾斜。同时，宝马加大了在自动驾驶和智能座舱领域的研发投入，试图通过技术创新重建竞争力。", "link": "https://www.bmw.com"}], "tech": [{"title": "AI视频Agent赛道爆发", "summary": "头部平台月算力消耗百万级，ARR可达2000万美元", "source": "36氪深度", "date": "5月7日", "badge": "重磅", "detail": "AI视频生成赛道正在经历大厂模型能力疯狂增长的巨大红利期。来自字节跳动的Seedance和快手的可灵这两款超级底座正在进行一周一小版、两月一大版的高频迭代，技术能力快速逼近专业影视制作水准。\n\n众多短剧、内容公司排队等待使用最新版模型已成为行业奇观。由此，在AI视频模型外套一层壳使其更简单易上手的AI视频Agent产品迎来增长奇迹。头部平台月算力消耗达百万元级别，ARR可达2000万美元。\n\n但创业公司也面临巨大挑战：如果大厂从模型层走到应用层，跟自己抢饭碗怎么办？业内判断，大厂会做但不会明天就做，这个窗口期可能还有3-5年。创业公司的护城河在于更早跑起来形成的用户留存与数据沉淀，以及越来越深的业务服务能力。", "link": "https://36kr.com"}, {"title": "腾讯、百度入股机器人灵巧手研发商", "summary": "投资临界点公司，智元机器人拆分业务独立发展", "source": "36氪", "date": "5月7日", "badge": "", "detail": "上海临界点创新智能科技有限公司近日发生工商变更，新增腾讯旗下上海启善投资有限公司、百度旗下三亚百川致新私募股权投资基金等重量级股东，注册资本由约554万人民币增至约597万人民币。\n\n该公司成立于2026年1月，由智元机器人将其灵巧手业务拆分而独立成立，是一家专注于机器人末端执行器，特别是灵巧手研发与生产的全球化科技公司。法定代表人为王闯，经营范围包括人工智能硬件销售、智能机器人销售及研发等。\n\n灵巧手被称为机器人的末端执行器，是实现精细化操作的关键部件。腾讯和百度的入局，显示出科技巨头对机器人产业链上游核心零部件的高度重视。随着人形机器人产业化加速，灵巧手市场规模预计将在未来五年内突破百亿元。", "link": "https://36kr.com"}, {"title": "宇树UniStore全面开放", "summary": "全球首个人形机器人任务动作应用商店上线", "source": "宇树科技", "date": "5月7日", "badge": "", "detail": "宇树科技宣布UniStore官方共享应用平台正式全面开放，这是全球首个人形机器人任务动作应用商店，标志着机器人软件生态建设迈出重要一步。\n\n开发者可以在平台上发布和销售机器人动作程序，用户可直接下载到宇树Go2、H1等人形机器人上执行。平台首批上线超过200个任务动作包，涵盖舞蹈、武术、搬运、巡检等多种场景。\n\nUniStore的推出借鉴了苹果App Store和Steam的模式，试图通过开放生态吸引更多开发者参与。宇树科技表示，平台将提供完善的分成机制，开发者可获得70%的收入。业内专家认为，硬件标准化加软件生态开放，是消费级机器人走向普及的必经之路。", "link": "https://www.unitree.com"}], "medical": [{"title": "AI辅助诊断首次通过国家药监局三类医疗器械审批", "summary": "某AI医疗影像公司研发的肺部CT辅助诊断系统正式获批，成为首个拿到三类证的AI影像产品，标志着AI医疗进入商业化新阶段。", "source": "医疗前沿", "date": "5月7日", "link": "https://www.nmpa.gov.cn", "detail": "国家药监局近日批准了首个AI医学影像辅助诊断三类医疗器械注册证，这是AI医疗领域的里程碑事件。\\n\\n该产品基于深度学习技术，可对肺部CT影像进行智能分析，辅助医生识别肺结节、磨玻璃影等异常病灶。临床试验数据显示，该产品在特定病灶识别上的敏感性超过95%，特异性超过90%，均达到临床可用标准。\\n\\n业内专家认为，这是AI医疗从科研走向临床的重要里程碑。三类证是医疗器械最高级别的注册认证，意味着产品可以在医院正式收费使用。这将推动更多AI医疗产品加速落地，预计2026年将有超过20款AI影像产品获批。", "badge": "重磅"}, {"title": "基因编辑疗法获批临床试验，有望根治地中海贫血", "summary": "国内首个体细胞基因编辑治疗产品获国家药监局批准开展临床试验，针对β-地中海贫血症，采用CRISPR-Cas9技术编辑患者自体造血干细胞。", "source": "生物医药观察", "date": "5月6日", "link": "https://www.cas.cn", "detail": "这是一款基于CRISPR-Cas9基因编辑技术的自体造血干细胞产品，通过编辑患者自身造血干细胞的BCL11A基因，重激活胎儿血红蛋白表达，从而根治β-地中海贫血。\\n\\n该疗法无需配型，一次给药即可终身获益。在地中海贫血高发地区如广东、广西，这一突破意义重大。中国约有30万中重型地贫患者，传统治疗依赖定期输血和祛铁，年均治疗费用超过10万元，且无法根治。\\n\\n此前该技术路线在海外已有成功案例。2024年，英国批准了首款CRISPR基因编辑疗法Casgevy上市，用于治疗镰状细胞病和β-地贫。此次国内获批标志着中国基因治疗领域迈上新台阶，有望让更多患者在家门口接受世界前沿治疗。", "badge": ""}, {"title": "可穿戴设备血糖监测技术获突破，无创检测精度提升", "summary": "某科技公司发布新一代无创血糖监测手环，采用光谱+AI算法，测量精度接近传统指尖血检测，已获CE认证。", "source": "健康科技日报", "date": "5月5日", "link": "https://tech.sina.com.cn", "detail": "该手环采用近红外光谱技术结合机器学习算法，通过皮肤间质液中的葡萄糖浓度间接推算血糖值。经过数千名糖尿病患者的临床验证，其MARD值（平均绝对相对差）已降至10%以内，接近FDA对连续血糖监测设备的要求。\\n\\n与传统指尖血检测相比，无创监测避免了频繁扎针的痛苦和感染风险，也降低了患者的监测成本。对于需要每天监测4-7次的糖尿病患者来说，这一技术将极大提升生活质量。\\n\\n产品预计2026年三季度在国内上市，定价约为进口CGM设备的三分之一。目前已获得欧盟CE认证，正在申请美国FDA和中国NMPA注册。公司计划未来扩展至血压、血氧等多项生理指标的监测，打造全方位的健康管理平台。", "badge": ""}, {"title": "全国医保谈判目录更新，7款创新药纳入报销", "summary": "2025年国家医保谈判初审名单公布，涉及肿瘤、罕见病、自免等领域的7款国产创新药通过形式审查。", "source": "医保局官网", "date": "5月7日", "link": "https://www.nhsa.gov.cn", "detail": "本次通过形式审查的7款创新药包括3款PD-1/PD-L1抑制剂、2款罕见病用药、1款自免疾病生物制剂和1款新型抗生素。这些药品均为2024年7月至2025年6月期间获批上市的新药。\\n\\nPD-1/PD-L1领域竞争尤为激烈。本次入围的3款国产新药分别针对肺癌、胃癌和肝癌，临床数据显示在特定人群中的疗效优于进口同类产品。罕见病用药方面，两款药物分别用于治疗脊髓性肌萎缩症（SMA）和法布雷病，年治疗费用原本超过百万元，纳入医保后患者自付部分有望降至10万元以内。\\n\\n通过形式审查后，这些药品将进入专家评审和谈判竞价环节。按照往年经验，谈判降价幅度通常在50%-70%之间。预计最终目录将于11月公布，2026年1月1日起执行。", "badge": ""}, {"title": "脑机接口辅助治疗抑郁症进入临床II期", "summary": "由国内医院联合科技公司开展的植入式脑机接口治疗难治性抑郁症研究完成II期入组，初步显示疗效显著。", "source": "神经科学前沿", "date": "5月4日", "link": "https://www.braininitiative.gov", "detail": "该研究采用深部脑刺激（DBS）结合闭环神经反馈技术，通过植入电极实时监测患者内侧前额叶皮层和杏仁核的神经活动，自动调整刺激参数。II期临床试验入组30例难治性抑郁症患者。\\n\\n治疗12周后，HAM-D（汉密尔顿抑郁量表）评分平均下降超过50%，其中40%患者达到临床缓解标准（评分≤7分）。这一疗效显著优于传统药物治疗，对于经历过至少两种抗抑郁药治疗无效的难治性患者而言，无疑是重大福音。\\n\\n这是国内首个脑机接口精神类疾病治疗的多中心临床试验，由上海某三甲医院牵头，联合多家医院和科技公司共同开展。如果III期试验顺利，预计2028年可申请医疗器械注册证，成为全球首个获批的脑机接口精神疾病治疗设备。", "badge": ""}], "education": [{"title": "教育部发布AI教育应用指南，中小学可引入智能助教", "summary": "教育部印发《中小学人工智能教育应用指南（试行）》，明确AI工具在教学辅助、个性化学习、作业批改等场景的使用规范。", "source": "教育部", "date": "5月7日", "link": "http://www.moe.gov.cn", "detail": "教育部近日印发《中小学人工智能教育应用指南（试行）》，这是国内首份专门针对AI在中小学教育场景应用的规范性文件。\\n\\n《指南》提出AI教育应用的三不原则：不得替代教师主导教学、不得直接用于学生成绩评定、不得收集学生生物特征等敏感信息。同时鼓励在备课辅助、学情分析、自适应练习等场景应用AI技术。例如，教师可以使用AI生成教学素材、分析班级学习薄弱点，学生可以获得个性化的错题推荐和学习路径规划。\\n\\n文件要求各地建立AI教育应用备案审查机制，确保技术供应商符合数据安全和未成年人保护要求。教育部表示，AI不是要取代教师，而是要成为教师的得力助手，让教师从重复性工作中解放出来，专注于更有创造性的教学互动。", "badge": "政策"}, {"title": "ChatGPT Edu中文版上线，面向高校提供免费学术版", "summary": "OpenAI联合国内云服务商推出ChatGPT Edu中文本地化版本，国内高校可免费申请使用，支持论文辅助、代码生成、数据分析等学术场景。", "source": "AI教育周刊", "date": "5月6日", "link": "https://openai.com/chatgpt/edu", "detail": "ChatGPT Edu中文版在模型能力上与国际版保持一致，但在数据合规上做了本地化部署，学术数据和对话内容不出境。高校可申请最高500个免费账号额度，支持团队共享、自定义GPTs、数据分析等高级功能。\\n\\n学术场景方面，ChatGPT Edu可辅助文献综述、论文写作、代码调试、数据分析等工作。OpenAI表示，与通用版不同，Edu版针对学术诚信做了特别优化，不会直接生成完整的学术论文，而是提供思路启发、结构建议和语言润色。\\n\\n目前已有清华、北大、浙大、复旦等50余所高校完成部署。北京大学表示，已在计算机、外语、经济等多个院系开展试点，教师反馈AI在批改作业和答疑方面效率提升了3倍以上。", "badge": ""}, {"title": "VR沉浸式教学系统进入千所学校，历史课走进金字塔", "summary": "国家虚拟现实/增强现实应用示范项目公布，VR历史、地理、生物沉浸式教学系统将在1000所中小学试点部署。", "source": "教育信息化", "date": "5月5日", "link": "http://www.moe.gov.cn", "detail": "该系统由国内VR教育公司开发，配套初高中历史、地理、生物三门学科的课程内容。学生戴上VR头显后可亲临古罗马斗兽场、深入人体血液循环系统、探索海底珊瑚礁生态系统。每个虚拟场景都配有语音讲解和互动问答环节。\\n\\n试点学校反馈显示，使用VR教学后学生课堂专注度提升40%以上，知识点记忆留存率提高25%。在历史课上，学生可以走进金字塔内部观察壁画细节；在生物课上，可以放大到细胞级别观察有丝分裂过程。\\n\\n教育部计划到2026年底覆盖全国1000所学校，2027年扩展至5000所。设备采用国产VR头显，单套成本已降至3000元以内，学校可通过专项教育信息化经费申请配置。", "badge": ""}, {"title": "职业教育法修订：产教融合型企业可获税收优惠", "summary": "新版《职业教育法》实施细则明确，深度参与产教融合的企业可享受增值税即征即退、所得税减免等税收优惠政策。", "source": "职业教育观察", "date": "5月7日", "link": "http://www.moe.gov.cn", "detail": "新版《职业教育法》实施细则近日发布，首次以法规形式明确了产教融合型企业的认定标准和税收优惠。\\n\\n细则定义深度参与的标准包括：与职业院校共建产业学院、接收学生实习实训不少于6个月、派遣技术人员担任兼职教师且每年授课不少于60学时等。符合条件的企业可按投资额的一定比例抵免当年应缴增值税，或享受15%的企业所得税优惠税率（正常税率为25%）。\\n\\n政策旨在解决长期以来企业参与职业教育动力不足的问题。据统计，全国超过80%的职业院校存在校企合作表面化现象，企业出于成本和效率考虑，不愿深度参与人才培养。此次税收优惠有望激活企业参与热情，推动职业教育真正对接产业需求。", "badge": ""}, {"title": "全国中小学课后服务升级，引入AI个性化辅导", "summary": "课后服务2.0行动计划启动，要求各地利用AI技术为参与课后服务的学生提供个性化作业辅导和兴趣培养方案。", "source": "基础教育周刊", "date": "5月4日", "link": "http://www.moe.gov.cn", "detail": "升级后的课后服务系统将利用AI学情诊断技术，在课后服务开始前30分钟完成对学生当日课堂学习情况的分析，自动生成针对性巩固练习和拓展内容。\\n\\n同时引入编程、机器人、3D设计等AI辅助创客课程。学生可以在课后服务时段学习Scratch编程、操控教育机器人、设计3D打印作品。AI系统会根据学生的兴趣和表现，推荐适合的学习路径。\\n\\n教育部要求2025年秋季学期覆盖全国50%以上义务教育学校，2026年实现全覆盖。经费方面，中央财政将安排专项资金支持AI课后服务平台建设，地方财政负责日常运营经费。家长只需支付少量基本费用，困难家庭可全额减免。", "badge": ""}], "aerospace": [{"title": "长征十二号首飞成功，商业航天迎来新运载工具", "summary": "新型运载火箭长征十二号在海南文昌成功首飞，太阳同步轨道运载能力达6吨，专为商业卫星星座部署设计。", "source": "中国航天报", "date": "5月7日", "link": "https://www.spacechina.com", "detail": "长征十二号是中国新一代中型运载火箭，采用液氧煤油发动机，全长约60米，起飞质量约430吨。该火箭最大的亮点是采用了一平两垂发射模式（水平转运、垂直总装、垂直测试），发射周期缩短至7天以内。\\n\\n其太阳同步轨道运载能力6吨，可满足大规模低轨卫星星座组网需求。首飞任务成功将3颗商业卫星送入预定轨道，验证了火箭的可靠性和商业发射服务能力。\\n\\n长征十二号的定位明确面向商业航天市场。随着中国低轨宽带星座、遥感星座等项目的推进，商业发射需求快速增长。长征十二号将与快舟、朱雀等民营火箭形成互补，构建覆盖不同运力需求的商业发射体系。", "badge": "首飞"}, {"title": "SpaceX星舰第五次轨道试飞成功，筷子式回收验证", "summary": "星舰第5次轨道级试飞实现助推器筷子式机械臂空中回收，飞船再入后海上软着陆，距完全复用仅一步之遥。", "source": "航天爱好者网", "date": "5月6日", "link": "https://www.spacex.com", "detail": "本次试飞中，超重助推器在发射约7分钟后返回发射塔，被机械臂在空中夹住完成回收，这是航天史上首次实现轨道级助推器的原位回收。星舰飞船部分在印度洋完成受控软着陆。\\n\\n马斯克表示，第6次试飞将尝试飞船的返回发射场回收，若成功则星舰系统将具备完全快速复用能力。届时，单次发射成本有望降至1000万美元以下，仅为当前猎鹰9号的五分之一。\\n\\n星舰的成功对人类航天具有里程碑意义。它是人类历史上最大的火箭，设计目标是将人类送上月球和火星。NASA已选择星舰作为阿尔忒弥斯计划的载人登月器，计划2027年实现宇航员重返月球。", "badge": ""}, {"title": "中国低轨宽带卫星星座首批组网星发射，对标星链", "summary": "国内某商业航天公司成功发射首批12颗低轨宽带通信卫星，计划三年内建成144颗卫星的星座，提供全球互联网接入服务。", "source": "卫星通信杂志", "date": "5月5日", "link": "https://www.cnsa.gov.cn", "detail": "该星座采用Ka和Ku频段，单星通信容量达30Gbps，重点服务海洋、航空、偏远地区等地面网络难以覆盖的区域。首批12颗卫星已完成在轨测试，实现了星间激光链路和用户终端连通演示。\\n\\n公司计划2027年前完成144颗卫星的一期组网，届时可向全球提供低延迟宽带互联网服务，终端下载速率可达百兆级。与SpaceX星链相比，该星座在覆盖亚太地区方面具有天然优势，且终端价格预计更低。\\n\\n低轨卫星互联网被视为6G通信的重要组成部分。中国已有多个低轨星座计划，总规模超过1.2万颗。本次发射标志着中国商业航天企业在卫星互联网领域的实质性突破。", "badge": ""}, {"title": "月球南极探测任务启动，中国探月四期工程展开", "summary": "探月四期工程正式立项，计划在2027年前后发射嫦娥七号、八号，开展月球南极资源勘查和原位资源利用技术验证。", "source": "深空探测实验室", "date": "5月4日", "link": "https://www.cnsa.gov.cn", "detail": "嫦娥七号将着陆在月球南极沙克尔顿撞击坑附近，携带飞跃器、轨道器、着陆器和巡视器，重点寻找水冰资源并评估其分布和储量。嫦娥八号将作为国际月球科研站的基本型，验证原位资源利用（ISRU）技术。\\n\\n月球南极是各国探月的焦点区域。由于存在永久阴影区，这里可能储存着大量水冰资源。水冰不仅可以转化为饮用水和氧气，还可以分解为氢和氧作为火箭推进剂，是建立月球基地的关键资源。\\n\\n这两项任务将为2030年前后的载人登月任务奠定技术和资源基础。中国计划在2030年前实现中国人首次登月，并在2035年前后建立国际月球科研站，开展长期科学研究和资源开发。", "badge": ""}, {"title": "超音速客机原型机完成首次试飞，4小时北京飞纽约", "summary": "Boom公司Overture超音速客机1/3缩比验证机XB-1完成首次超音速试飞，商业版预计2029年首飞，巡航速度2.2马赫。", "source": "航空周刊", "date": "5月3日", "link": "https://boomsupersonic.com", "detail": "XB-1验证机在莫哈韦沙漠上空首次突破音障，达到1.1马赫的速度。该验证机用于测试超音速飞行的气动布局、飞控系统和降噪技术。商业版Overture预计2029年首飞，2030年投入商业运营。\\n\\nOverture商业客机将采用三角翼+可变几何进气道设计，搭载4台涡扇发动机，可搭载65-88名乘客，航程约8300公里，巡航速度2.2马赫。这意味着从北京到纽约的飞行时间将从目前的13小时缩短至4小时。\\n\\n燃油效率相比协和号提升75%，解决了上一代超音速客机高油耗、高噪音的核心问题。目前已有美联航、日航等航空公司签署采购意向，累计订单超过130架。票价预计为传统商务舱的1.5倍，面向高端商务旅客。", "badge": ""}], "products": [{"title": "三星退出中国家电市场", "summary": "宣布停止在中国大陆销售所有家电产品", "source": "三星新闻", "date": "5月7日", "badge": "重大", "detail": "三星电子正式宣布停止在中国大陆市场销售所有家电产品，包括冰箱、洗衣机、空调、电视等全线白电及黑电产品。这一决定标志着三星在中国消费电子市场的全面撤退。\n\n公司表示未来将聚焦手机、半导体、显示面板等核心业务在华发展。事实上，三星在中国的家电业务近年来持续萎缩，市场份额已被海尔、美的、格力等本土品牌远远甩在身后。在高端市场，索尼、博西家电（博世+西门子）也占据了更有利的位置。\n\n回顾三星的在华历程，公司曾在2019年关闭惠州手机工厂，将制造业务转移到越南和印度。如今家电业务的退出，是三星全球化战略调整的最新一步。分析师认为，中国家电市场竞争异常激烈，价格战频繁，外资品牌盈利空间被严重压缩，退出是理性的商业决策。", "link": "https://news.samsung.com"}, {"title": "一加 Ace 6 至尊版发布", "summary": "定位颗秒神器，性能操控赛旗舰", "source": "一加官网", "date": "5月6日", "badge": "", "detail": "一加正式发布Ace 6至尊版手机，这款手机被官方定位为颗秒神器，主打极致性能和游戏体验。核心配置方面，搭载骁龙8至尊版处理器，配备120Hz LTPO自适应刷新率屏幕和5400mAh大电池，支持100W超级闪充。\n\n游戏体验是这款手机的最大亮点。一加为其搭载了超帧超画引擎，通过AI算法将游戏帧率提升至120帧，同时增强画面细节。官方表示，目前已有超过100款主流游戏支持该功能，包括《王者荣耀》《和平精英》《原神》等。\n\n起售价2999元（12+256GB版本），定位中高端性能旗舰。一加表示，Ace系列的使命是为追求极致性能的用户提供高性价比选择，与数字系列形成互补。该机型将于5月15日首销。", "link": "https://www.oneplus.com"}], "auto": [{"title": "巴西5月11日起对中国公民免签", "summary": "每次入境最长可停留30天，赴巴西机票搜索量猛增", "source": "巴西政府", "date": "5月7日", "badge": "免签", "detail": "巴西政府5月7日正式宣布，自2026年5月11日起，对持普通护照的中国公民实施免签入境政策。根据巴西外交部发布的公报，持普通护照的中华人民共和国公民可享受短期免签入境，每次入境最长可停留30天。\n\n消息发布后，中国旅游市场反应热烈。去哪儿旅行指数显示，截至5月7日晚8点半，飞赴巴西里约热内卢搜索量环比上一小时翻倍，环比上周增近2倍；飞赴巴西利亚机票搜索量环比前一小时增2倍，环比上周大增4.5倍。\n\n巴西是南美洲最大的国家，拥有里约热内卢、亚马逊雨林、伊瓜苏瀑布等世界级旅游资源。此前中国公民赴巴西需办理签证，流程相对繁琐。免签政策的实施，预计将大幅提升中国游客赴南美旅游的热情，也有望带动中巴之间的商务往来。", "link": "https://www.gov.br"}, {"title": "本田叫停加拿大电动汽车工厂计划", "summary": "美国市场需求疲软，原定2028年开工项目无限期冻结", "source": "本田全球", "date": "5月6日", "badge": "", "detail": "本田汽车公司决定无限期冻结在加拿大建设电动汽车工厂的计划，这是全球汽车产业电动化转型遇阻的最新信号。该项目连同配套电池工厂总计投资150亿加元（约110亿美元），原定于2028年开工。\n\n本田做出这一决定的直接原因是美国市场需求疲软。2026年第一季度，本田在美国市场的电动车销量仅为预期的60%，库存积压严重。同时，美国政策环境的不确定性——包括可能的关税调整和补贴政策变化——也让本田对未来的投资回报产生疑虑。\n\n值得注意的是，本田去年已将开工日期延后两年，如今彻底叫停。这一决定不仅影响本田自身的电动化战略，也对加拿大的汽车产业链造成冲击。安大略省政府此前已为该项目提供了超过10亿加元的税收优惠和基础设施支持。", "link": "https://global.honda"}], "vc": [{"title": "像素绽放PixelBloom完成C轮融资", "summary": "全面发力AI办公Agent，从一分钟生成PPT到交付商用级结果", "source": "36氪", "date": "5月7日", "badge": "融资", "detail": "AI办公解决方案公司像素绽放PixelBloom完成C轮融资，投资方包括红杉中国和多家知名美元基金。本轮融资后，公司将全面发力AI办公Agent方向，从内容生成拓展到商用交付的全流程解决方案。\n\n像素绽放此前以AI生成PPT工具Pixso和AiPPT闻名，用户量已突破千万。其产品可在1分钟内根据用户输入的主题自动生成完整PPT，包括大纲、配图和排版。在2025年，公司进一步推出了AI数据分析报告、AI合同审查等办公场景应用。\n\n新融资将重点用于三个方面：一是扩充Agent产品矩阵，覆盖更多办公场景；二是建立企业级服务团队，为大客户提供定制化交付；三是拓展海外市场，特别是东南亚和中东地区。创始人表示，AI办公Agent的目标是让每个职场人拥有专属的AI助理，将重复性工作效率提升10倍以上。", "link": "https://36kr.com"}, {"title": "LiblibAI完成1.3亿美元B轮融资", "summary": "红杉中国、CMC资本投资，一年内连续四轮融资", "source": "36氪", "date": "5月7日", "badge": "", "detail": "AI视频创作平台LibTV母公司LiblibAI在去年10月完成由红杉中国、CMC资本等机构投资的1.3亿美元B轮融资，创下一年内连续四轮融资的行业纪录，成为2025年创投市场最活跃的公司之一。\n\nLiblibAI的核心产品LibTV是一个AI驱动的视频创作平台，用户可以通过自然语言描述生成短视频、广告片和动画内容。平台集成了文本生成、图像生成和视频生成等多种AI能力，创作者无需专业技能即可制作高质量视频。\n\n完成B轮融资后，母公司估值超过10亿美元，跻身AI视频赛道独角兽行列。公司表示，资金将主要用于模型训练、算力扩充和海外市场拓展。目前LibTV的海外版已在美国和欧洲上线，月活用户超过500万。竞争对手包括Runway、Pika Labs等国际知名AI视频公司。", "link": "https://36kr.com"}]};

// ===== State =====
let currentFilter = 'all';
let favorites = JSON.parse(localStorage.getItem('newsFavorites') || '[]');

// ===== Reading Progress =====
function updateReadingProgress() {
  const scrollTop = window.scrollY;
  const docHeight = document.documentElement.scrollHeight - window.innerHeight;
  const progress = (scrollTop / docHeight) * 100;
  document.querySelector('.reading-progress').style.width = progress + '%';
}
window.addEventListener('scroll', updateReadingProgress, { passive: true });

// ===== Back to Top =====
const backToTop = document.querySelector('.back-to-top');
window.addEventListener('scroll', () => {
  if (window.scrollY > 500) {
    backToTop.classList.add('visible');
  } else {
    backToTop.classList.remove('visible');
  }
}, { passive: true });
backToTop.addEventListener('click', () => {
  window.scrollTo({ top: 0, behavior: 'smooth' });
});

// ===== Theme Toggle =====
const themeBtn = document.getElementById('themeBtn');
if (themeBtn) {
  themeBtn.addEventListener('click', toggleTheme);
}
function toggleTheme() {
  document.body.classList.toggle('dark');
  const isDark = document.body.classList.contains('dark');
  localStorage.setItem('theme', isDark ? 'dark' : 'light');
  if (themeBtn) themeBtn.textContent = isDark ? '☀️' : '🌙';
}
const savedTheme = localStorage.getItem('theme');
if (savedTheme === 'dark') {
  document.body.classList.add('dark');
  if (themeBtn) themeBtn.textContent = '☀️';
}

// ===== Mobile Menu =====
const mobileMenuBtn = document.getElementById('mobileMenuBtn');
const mobileNav = document.getElementById('mobileNav');
if (mobileMenuBtn) {
  mobileMenuBtn.addEventListener('click', () => {
    mobileNav.classList.toggle('active');
  });
}

// ===== Scroll Reveal =====
const observerOptions = { root: null, rootMargin: '0px', threshold: 0.1 };
const revealObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
      revealObserver.unobserve(entry.target);
    }
  });
}, observerOptions);
document.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));

// ===== Active Nav Link =====
const sections = document.querySelectorAll('section[id]');
const navLinks = document.querySelectorAll('.nav-links a');
function updateActiveNav() {
  let current = '';
  sections.forEach(section => {
    const sectionTop = section.offsetTop;
    if (window.scrollY >= sectionTop - 200) {
      current = section.getAttribute('id');
    }
  });
  navLinks.forEach(link => {
    link.classList.remove('active');
    if (link.getAttribute('href') === '#' + current) {
      link.classList.add('active');
    }
  });
}
window.addEventListener('scroll', updateActiveNav, { passive: true });

// ===== Search =====
const searchInput = document.getElementById('searchInput');
if (searchInput) {
  searchInput.addEventListener('input', (e) => {
    const query = e.target.value.toLowerCase();
    filterNews(query, currentFilter);
  });
}

// ===== Filter Tags =====
function setFilter(filter) {
  currentFilter = filter;
  document.querySelectorAll('.filter-tag').forEach(tag => {
    tag.classList.toggle('active', tag.dataset.filter === filter);
  });
  const query = searchInput ? searchInput.value.toLowerCase() : '';
  filterNews(query, filter);
}

document.querySelectorAll('.filter-tag').forEach(tag => {
  tag.addEventListener('click', () => setFilter(tag.dataset.filter));
});

// ===== Filter News =====
function filterNews(query, category) {
  let hasResults = false;
  
  Object.keys(newsData).forEach(key => {
    const section = document.getElementById(key);
    if (!section) return;
    
    if (category !== 'all' && category !== key) {
      section.classList.add('hidden');
      return;
    }
    section.classList.remove('hidden');
    
    const cards = section.querySelectorAll('.news-card');
    let sectionHasResults = false;
    
    cards.forEach(card => {
      const title = card.querySelector('h3').textContent.toLowerCase();
      const summary = card.querySelector('p').textContent.toLowerCase();
      const matches = title.includes(query) || summary.includes(query);
      
      if (matches) {
        card.classList.remove('hidden');
        sectionHasResults = true;
        hasResults = true;
      } else {
        card.classList.add('hidden');
      }
    });
    
    // Update section count
    const countEl = section.querySelector('.section-count');
    if (countEl) {
      const visibleCards = section.querySelectorAll('.news-card:not(.hidden)');
      countEl.textContent = visibleCards.length + ' 条';
    }
  });
  
  // Show no results message
  let noResults = document.querySelector('.no-results');
  if (!hasResults) {
    if (!noResults) {
      noResults = document.createElement('div');
      noResults.className = 'no-results';
      noResults.innerHTML = `
        <div class="no-results-icon">🔍</div>
        <h3>未找到相关资讯</h3>
        <p>尝试其他关键词或切换分类</p>
      `;
      document.querySelector('main').appendChild(noResults);
    }
    noResults.style.display = 'block';
  } else if (noResults) {
    noResults.style.display = 'none';
  }
}

// ===== Image Loading =====
function initImageLoading() {
  document.querySelectorAll('.card-image').forEach(img => {
    if (img.complete) {
      img.classList.add('loaded');
      const skeleton = img.parentElement.querySelector('.skeleton-bg');
      if (skeleton) skeleton.remove();
    } else {
      img.addEventListener('load', () => {
        img.classList.add('loaded');
        const skeleton = img.parentElement.querySelector('.skeleton-bg');
        if (skeleton) skeleton.remove();
      });
      img.addEventListener('error', () => {
        const skeleton = img.parentElement.querySelector('.skeleton-bg');
        if (skeleton) skeleton.remove();
        img.style.display = 'none';
      });
    }
  });
}

// ===== Modal =====
const modalOverlay = document.getElementById('modalOverlay');
const modalClose = document.getElementById('modalClose');
const modalImg = document.getElementById('modalImg');
const modalTitle = document.getElementById('modalTitle');
const modalMeta = document.getElementById('modalMeta');
const modalContent = document.getElementById('modalContent');
const modalBadge = document.getElementById('modalBadge');
const modalLink = document.getElementById('modalLink');

let currentModalData = null;

function openModal(data, imgSrc) {
  currentModalData = data;
  modalImg.src = imgSrc || '';
  modalImg.style.display = imgSrc ? 'block' : 'none';
  modalTitle.textContent = data.title;
  modalMeta.textContent = `${data.source} · ${data.date}`;
  
  // Format detail text
  let content = data.detail || data.summary;
  content = content.replace(/\\n\\n/g, '</p><p>').replace(/\\n/g, ' ');
  if (!content.startsWith('<p>')) content = '<p>' + content + '</p>';
  modalContent.innerHTML = content;
  
  if (data.badge) {
    modalBadge.textContent = data.badge;
    modalBadge.style.display = 'inline-block';
  } else {
    modalBadge.style.display = 'none';
  }
  
  if (data.link) {
    modalLink.href = data.link;
    modalLink.style.display = 'inline-flex';
  } else {
    modalLink.style.display = 'none';
  }
  
  modalOverlay.classList.add('active');
  document.body.style.overflow = 'hidden';
}

function closeModal() {
  modalOverlay.classList.remove('active');
  document.body.style.overflow = '';
  currentModalData = null;
}

if (modalClose) modalClose.addEventListener('click', closeModal);
if (modalOverlay) {
  modalOverlay.addEventListener('click', (e) => {
    if (e.target === modalOverlay) closeModal();
  });
}
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') closeModal();
});

// ===== Card Click =====
document.querySelectorAll('.news-card').forEach(card => {
  card.addEventListener('click', (e) => {
    if (e.target.closest('.card-action-btn')) return;
    
    const gridId = card.dataset.grid;
    const index = parseInt(card.dataset.index);
    const sectionKey = gridId.replace('-grid', '');
    const data = newsData[sectionKey][index];
    const img = card.querySelector('.card-image');
    const imgSrc = img && img.src ? img.src : '';
    openModal(data, imgSrc);
  });
});

// ===== Favorite =====
function toggleFavorite(e, cardId) {
  e.stopPropagation();
  const btn = e.currentTarget;
  const index = favorites.indexOf(cardId);
  
  if (index > -1) {
    favorites.splice(index, 1);
    btn.classList.remove('active');
    btn.textContent = '🤍';
    showToast('已取消收藏');
  } else {
    favorites.push(cardId);
    btn.classList.add('active');
    btn.textContent = '❤️';
    showToast('已收藏');
  }
  
  localStorage.setItem('newsFavorites', JSON.stringify(favorites));
}

// ===== Share =====
async function shareNews(e, title, summary) {
  e.stopPropagation();
  
  if (navigator.share) {
    try {
      await navigator.share({
        title: title,
        text: summary,
        url: window.location.href
      });
    } catch (err) {
      // User cancelled
    }
  } else {
    // Copy to clipboard
    const text = `${title}\n${summary}\n${window.location.href}`;
    navigator.clipboard.writeText(text).then(() => {
      showToast('链接已复制到剪贴板');
    });
  }
}

function shareModalNews() {
  if (currentModalData) {
    shareNews({ stopPropagation: () => {} }, currentModalData.title, currentModalData.summary);
  }
}

// ===== Toast =====
function showToast(message) {
  let toast = document.querySelector('.toast');
  if (!toast) {
    toast = document.createElement('div');
    toast.className = 'toast';
    document.body.appendChild(toast);
  }
  toast.textContent = message;
  toast.classList.add('show');
  setTimeout(() => toast.classList.remove('show'), 2000);
}

// ===== Init =====
document.addEventListener('DOMContentLoaded', () => {
  initImageLoading();
  updateActiveNav();
  
  // Update section counts
  Object.keys(newsData).forEach(key => {
    const section = document.getElementById(key);
    if (section) {
      const countEl = section.querySelector('.section-count');
      if (countEl) {
        countEl.textContent = newsData[key].length + ' 条';
      }
    }
  });
  
  // Restore favorite buttons state
  favorites.forEach(id => {
    const card = document.querySelector(`[onclick*="'${id}'"]`);
    if (card) {
      card.classList.add('active');
      card.textContent = '❤️';
    }
  });
});
